// Generated by Claude Sonnet 4.6

import mockAxios from 'axios';

import { createWorkspace } from '@/services/backend-client/devWorkspaceApi';
import devfileApi from '@/services/devfileApi';

describe('DevWorkspace API', () => {
  const mockPost = mockAxios.post as jest.Mock;

  afterEach(() => {
    jest.resetAllMocks();
  });

  describe('createWorkspace', () => {
    it('should create workspace without restore fields (regression test)', async () => {
      const devworkspace = {
        apiVersion: 'workspace.devfile.io/v1alpha2',
        kind: 'DevWorkspace',
        metadata: {
          name: 'new-workspace',
          namespace: 'user-che',
        },
        spec: {
          started: true,
          template: {},
        },
      } as devfileApi.DevWorkspace;

      const mockHeaders = { 'content-type': 'application/json' };
      mockPost.mockResolvedValueOnce({
        data: devworkspace,
        headers: mockHeaders,
      });

      const result = await createWorkspace(devworkspace);

      expect(mockPost).toHaveBeenCalled();
      expect(mockPost.mock.calls[0][0]).toBe('/dashboard/api/namespace/user-che/devworkspaces');
      // Ensure no restoreFromBackup or backupImageUrl fields in the request body
      const requestBody = mockPost.mock.calls[0][1];
      expect(requestBody).toEqual({ devworkspace });
      expect(requestBody).not.toHaveProperty('restoreFromBackup');
      expect(requestBody).not.toHaveProperty('backupImageUrl');

      expect(result.devWorkspace).toEqual(devworkspace);
      expect(result.headers).toEqual(mockHeaders);
    });
  });
});
